create extension if not exists pgcrypto;
create type public.brainstorm_session_status as enum ('WAITING','PRESENTING','IDEATION_OPEN','IDEATION_CLOSED','AI_GROUPING','GROUP_REVIEW','VOTING_OPEN','VOTING_WAITING','RESULTS','FINISHED');
create type public.brainstorm_grouping_method as enum ('ai','manual','individual');
create table public.brainstorm_areas(id uuid primary key default gen_random_uuid(),name text not null unique,slug text not null unique,display_order int not null default 0,active boolean not null default true);
create table public.brainstorm_sessions(id uuid primary key default gen_random_uuid(),code varchar(20) not null unique check(code ~ '^[A-Z0-9]+$'),title varchar(120) not null,status public.brainstorm_session_status not null default 'WAITING',current_round_id uuid,current_consolidated_idea_id uuid,stage_started_at timestamptz,stage_ends_at timestamptz,admin_pin_hash text not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.brainstorm_participants(id uuid primary key default gen_random_uuid(),session_id uuid not null references public.brainstorm_sessions on delete cascade,anonymous_token uuid not null,primary_area_id uuid not null references public.brainstorm_areas,created_at timestamptz not null default now(),last_seen_at timestamptz not null default now(),unique(session_id,anonymous_token));
create table public.brainstorm_rounds(id uuid primary key default gen_random_uuid(),session_id uuid not null references public.brainstorm_sessions on delete cascade,area_id uuid not null references public.brainstorm_areas,title varchar(120) not null,question varchar(500) not null,supporting_text varchar(500),display_order int not null,duration_seconds int not null default 300 check(duration_seconds between 30 and 7200),status text not null default 'draft',created_at timestamptz not null default now(),unique(session_id,display_order));
alter table public.brainstorm_sessions add constraint sessions_current_round_fk foreign key(current_round_id) references public.brainstorm_rounds on delete set null;
create table public.brainstorm_ideas(id uuid primary key default gen_random_uuid(),session_id uuid not null references public.brainstorm_sessions on delete cascade,round_id uuid not null references public.brainstorm_rounds on delete cascade,area_id uuid not null references public.brainstorm_areas,participant_id uuid not null references public.brainstorm_participants on delete cascade,text varchar(500) not null check(length(trim(text)) between 2 and 500),expected_result varchar(500),created_at timestamptz not null default now());
create table public.brainstorm_consolidated_ideas(id uuid primary key default gen_random_uuid(),session_id uuid not null references public.brainstorm_sessions on delete cascade,area_id uuid not null references public.brainstorm_areas,title varchar(160) not null,description varchar(800) not null,grouping_method public.brainstorm_grouping_method not null,grouping_confidence numeric(4,3) check(grouping_confidence between 0 and 1),approved boolean not null default false,display_order int not null default 0,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
alter table public.brainstorm_sessions add constraint sessions_current_idea_fk foreign key(current_consolidated_idea_id) references public.brainstorm_consolidated_ideas on delete set null;
create table public.brainstorm_consolidated_idea_sources(consolidated_idea_id uuid not null references public.brainstorm_consolidated_ideas on delete cascade,idea_id uuid not null references public.brainstorm_ideas on delete cascade,primary key(consolidated_idea_id,idea_id),unique(idea_id));
create table public.brainstorm_votes(id uuid primary key default gen_random_uuid(),session_id uuid not null references public.brainstorm_sessions on delete cascade,consolidated_idea_id uuid not null references public.brainstorm_consolidated_ideas on delete cascade,participant_id uuid not null references public.brainstorm_participants on delete cascade,participant_area_id uuid not null references public.brainstorm_areas,area_weight numeric(3,2) not null check(area_weight between 1 and 2),revenue smallint not null check(revenue between 1 and 5),margin smallint not null check(margin between 1 and 5),savings smallint not null check(savings between 1 and 5),ease smallint not null check(ease between 1 and 5),speed smallint not null check(speed between 1 and 5),scalability smallint not null check(scalability between 1 and 5),automation smallint not null check(automation between 1 and 5),risk smallint not null check(risk between 1 and 5),customer smallint not null check(customer between 1 and 5),strategy smallint not null check(strategy between 1 and 5),created_at timestamptz not null default now(),unique(session_id,consolidated_idea_id,participant_id));
create index brainstorm_participants_session_idx on public.brainstorm_participants(session_id);create index brainstorm_ideas_round_idx on public.brainstorm_ideas(round_id);create index brainstorm_ideas_participant_idx on public.brainstorm_ideas(participant_id);create index brainstorm_consolidated_session_idx on public.brainstorm_consolidated_ideas(session_id,approved);create index brainstorm_votes_idea_idx on public.brainstorm_votes(consolidated_idea_id);
alter table public.brainstorm_areas enable row level security;alter table public.brainstorm_sessions enable row level security;alter table public.brainstorm_participants enable row level security;alter table public.brainstorm_rounds enable row level security;alter table public.brainstorm_ideas enable row level security;alter table public.brainstorm_consolidated_ideas enable row level security;alter table public.brainstorm_consolidated_idea_sources enable row level security;alter table public.brainstorm_votes enable row level security;
create policy areas_read on public.brainstorm_areas for select to anon using(active);create policy sessions_read on public.brainstorm_sessions for select to anon using(true);create policy rounds_read on public.brainstorm_rounds for select to anon using(true);create policy approved_groups_read on public.brainstorm_consolidated_ideas for select to anon using(approved);create policy participant_restore on public.brainstorm_participants for select to anon using(true);create policy own_ideas_read on public.brainstorm_ideas for select to anon using(true);
revoke insert,update,delete on table public.brainstorm_areas,public.brainstorm_sessions,public.brainstorm_participants,public.brainstorm_rounds,public.brainstorm_ideas,public.brainstorm_consolidated_ideas,public.brainstorm_consolidated_idea_sources,public.brainstorm_votes from anon;revoke select on public.brainstorm_votes,public.brainstorm_consolidated_idea_sources from anon;grant select on public.brainstorm_areas,public.brainstorm_sessions,public.brainstorm_participants,public.brainstorm_rounds,public.brainstorm_ideas,public.brainstorm_consolidated_ideas to anon;
create or replace function public.brainstorm_join_session(p_session_code text,p_anonymous_token uuid,p_area_id uuid) returns setof public.brainstorm_participants language plpgsql security definer set search_path='' as $$ begin return query insert into public.brainstorm_participants(session_id,anonymous_token,primary_area_id) select s.id,p_anonymous_token,p_area_id from public.brainstorm_sessions s join public.brainstorm_areas a on a.id=p_area_id and a.active where s.code=upper(p_session_code) on conflict(session_id,anonymous_token) do update set last_seen_at=now() returning *;end$$;
create or replace function public.brainstorm_submit_idea(p_session_id uuid,p_round_id uuid,p_participant_id uuid,p_token uuid,p_text text,p_expected_result text default null) returns public.brainstorm_ideas language plpgsql security definer set search_path='' as $$ declare outrow public.brainstorm_ideas;begin if length(trim(p_text)) not between 2 and 500 or length(coalesce(p_expected_result,''))>500 then raise exception 'Texto inválido';end if;if not exists(select 1 from public.brainstorm_sessions s join public.brainstorm_rounds r on r.id=p_round_id and r.session_id=s.id join public.brainstorm_participants p on p.id=p_participant_id and p.session_id=s.id where s.id=p_session_id and s.status='IDEATION_OPEN' and p.anonymous_token=p_token) then raise exception 'Contribuição não permitida';end if;if (select count(*) from public.brainstorm_ideas where participant_id=p_participant_id and round_id=p_round_id)>=20 then raise exception 'Limite de ideias atingido';end if;insert into public.brainstorm_ideas(session_id,round_id,area_id,participant_id,text,expected_result) select p_session_id,p_round_id,r.area_id,p_participant_id,trim(p_text),nullif(trim(p_expected_result),'') from public.brainstorm_rounds r where r.id=p_round_id returning * into outrow;return outrow;end$$;
create or replace function public.brainstorm_submit_vote(p_session_id uuid,p_idea_id uuid,p_participant_id uuid,p_token uuid,p_ratings jsonb) returns uuid language plpgsql security definer set search_path='' as $$ declare out_id uuid;pa uuid;ia uuid;w numeric;begin select p.primary_area_id,c.area_id into pa,ia from public.brainstorm_participants p join public.brainstorm_consolidated_ideas c on c.id=p_idea_id join public.brainstorm_sessions s on s.id=p_session_id where p.id=p_participant_id and p.session_id=s.id and p.anonymous_token=p_token and c.session_id=s.id and c.approved and s.status='VOTING_OPEN' and s.current_consolidated_idea_id=c.id;if pa is null then raise exception 'Voto não permitido';end if;w:=case when pa=ia and not exists(select 1 from public.brainstorm_areas a where a.id=ia and a.slug in ('diretoria','outro')) then 1.30 else 1 end;insert into public.brainstorm_votes(session_id,consolidated_idea_id,participant_id,participant_area_id,area_weight,revenue,margin,savings,ease,speed,scalability,automation,risk,customer,strategy) values(p_session_id,p_idea_id,p_participant_id,pa,w,(p_ratings->>'revenue')::int,(p_ratings->>'margin')::int,(p_ratings->>'savings')::int,(p_ratings->>'ease')::int,(p_ratings->>'speed')::int,(p_ratings->>'scalability')::int,(p_ratings->>'automation')::int,(p_ratings->>'risk')::int,(p_ratings->>'customer')::int,(p_ratings->>'strategy')::int) returning id into out_id;return out_id;end$$;
create or replace function public.brainstorm_verify_admin_pin(p_code text,p_pin text) returns boolean language sql security definer set search_path='' as $$select exists(select 1 from public.brainstorm_sessions where code=upper(p_code) and admin_pin_hash=extensions.crypt(p_pin,admin_pin_hash))$$;
revoke execute on function public.brainstorm_join_session(text,uuid,uuid),public.brainstorm_submit_idea(uuid,uuid,uuid,uuid,text,text),public.brainstorm_submit_vote(uuid,uuid,uuid,uuid,jsonb),public.brainstorm_verify_admin_pin(text,text) from public;grant execute on function public.brainstorm_join_session(text,uuid,uuid),public.brainstorm_submit_idea(uuid,uuid,uuid,uuid,text,text),public.brainstorm_submit_vote(uuid,uuid,uuid,uuid,jsonb) to anon;grant execute on function public.brainstorm_verify_admin_pin(text,text) to service_role;
create view public.brainstorm_published_results with(security_invoker=true) as select c.id,c.session_id,c.area_id,c.title,c.description,count(distinct v.id)::int vote_count,count(distinct src.idea_id)::int contribution_count,round(sum(v.revenue*v.area_weight)/nullif(sum(v.area_weight),0),2) revenue,round(sum(v.margin*v.area_weight)/nullif(sum(v.area_weight),0),2) margin,round(sum(v.savings*v.area_weight)/nullif(sum(v.area_weight),0),2) savings,round(sum(v.ease*v.area_weight)/nullif(sum(v.area_weight),0),2) ease,round(sum(v.speed*v.area_weight)/nullif(sum(v.area_weight),0),2) speed,round(sum(v.scalability*v.area_weight)/nullif(sum(v.area_weight),0),2) scalability,round(sum(v.automation*v.area_weight)/nullif(sum(v.area_weight),0),2) automation,round(sum(v.risk*v.area_weight)/nullif(sum(v.area_weight),0),2) risk,round(sum(v.customer*v.area_weight)/nullif(sum(v.area_weight),0),2) customer,round(sum(v.strategy*v.area_weight)/nullif(sum(v.area_weight),0),2) strategy from public.brainstorm_consolidated_ideas c join public.brainstorm_sessions s on s.id=c.session_id and s.status in('RESULTS','FINISHED') left join public.brainstorm_votes v on v.consolidated_idea_id=c.id left join public.brainstorm_consolidated_idea_sources src on src.consolidated_idea_id=c.id where c.approved group by c.id;
grant select on public.brainstorm_published_results to anon;alter publication supabase_realtime add table public.brainstorm_sessions;
